import{_ as a,o as n,c as e,a4 as s}from"./chunks/framework._in6GHBg.js";const g=JSON.parse('{"title":"概率统计套路","description":"","frontmatter":{},"headers":[],"relativePath":"math/Math-Review-Routine-008-概率统计套路-V1.0-20260405.md","filePath":"math/Math-Review-Routine-008-概率统计套路-V1.0-20260405.md"}'),l={name:"math/Math-Review-Routine-008-概率统计套路-V1.0-20260405.md"};function i(p,t,r,d,o,c){return n(),e("div",null,[...t[0]||(t[0]=[s(`<h1 id="概率统计套路" tabindex="-1">概率统计套路 <a class="header-anchor" href="#概率统计套路" aria-label="Permalink to &quot;概率统计套路&quot;">​</a></h1><p><strong>识别模型→套用公式→计算验证</strong></p><hr><h2 id="一、题型识别" tabindex="-1">一、题型识别 <a class="header-anchor" href="#一、题型识别" aria-label="Permalink to &quot;一、题型识别&quot;">​</a></h2><h3 id="特征关键词" tabindex="-1">特征关键词 <a class="header-anchor" href="#特征关键词" aria-label="Permalink to &quot;特征关键词&quot;">​</a></h3><ul><li>&quot;排列组合&quot;</li><li>&quot;概率&quot;</li><li>&quot;分布列&quot;</li><li>&quot;期望&quot;</li><li>&quot;方差&quot;</li><li>&quot;统计案例&quot;</li></ul><h3 id="典型问法" tabindex="-1">典型问法 <a class="header-anchor" href="#典型问法" aria-label="Permalink to &quot;典型问法&quot;">​</a></h3><ul><li>从n个球中取m个，有多少种取法？</li><li>某事件发生的概率是多少？</li><li>求随机变量X的分布列和期望</li><li>是否有95%的把握认为...与...有关？</li></ul><hr><h2 id="二、解题步骤" tabindex="-1">二、解题步骤 <a class="header-anchor" href="#二、解题步骤" aria-label="Permalink to &quot;二、解题步骤&quot;">​</a></h2><h3 id="类型1-计数问题-排列组合" tabindex="-1">类型1：计数问题（排列组合） <a class="header-anchor" href="#类型1-计数问题-排列组合" aria-label="Permalink to &quot;类型1：计数问题（排列组合）&quot;">​</a></h3><p><strong>Step 1：判断有序/无序</strong></p><ul><li>有序→排列A(n,m)</li><li>无序→组合C(n,m)</li></ul><p><strong>Step 2：判断分类/分步</strong></p><ul><li>分类→加法</li><li>分步→乘法</li></ul><p><strong>Step 3：计算</strong></p><ul><li>A(n,m) = n!/(n-m)!</li><li>C(n,m) = n!/[m!(n-m)!]</li></ul><p><strong>常见类型</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:center;">类型</th><th style="text-align:left;">方法</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>相邻问题</strong></td><td style="text-align:left;">捆绑法</td></tr><tr><td style="text-align:center;"><strong>不相邻问题</strong></td><td style="text-align:left;">插空法</td></tr><tr><td style="text-align:center;"><strong>定序问题</strong></td><td style="text-align:left;">除法（先全排再除以定序排列数）</td></tr><tr><td style="text-align:center;"><strong>分组问题</strong></td><td style="text-align:left;">注意平均分组要除以组数的阶乘</td></tr><tr><td style="text-align:center;"><strong>隔板法</strong></td><td style="text-align:left;">相同元素分给不同对象</td></tr></tbody></table><hr><h3 id="类型2-古典概型" tabindex="-1">类型2：古典概型 <a class="header-anchor" href="#类型2-古典概型" aria-label="Permalink to &quot;类型2：古典概型&quot;">​</a></h3><p><strong>Step 1：确定总基本事件数n</strong></p><p><strong>Step 2：确定事件A包含的基本事件数m</strong></p><p><strong>Step 3：计算P(A) = m/n</strong></p><p><strong>关键</strong>：</p><ul><li>确保等可能性</li><li>不重不漏</li></ul><hr><h3 id="类型3-条件概率与独立事件" tabindex="-1">类型3：条件概率与独立事件 <a class="header-anchor" href="#类型3-条件概率与独立事件" aria-label="Permalink to &quot;类型3：条件概率与独立事件&quot;">​</a></h3><p><strong>条件概率</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>P(B|A) = P(A∩B)/P(A)</span></span></code></pre></div><p><strong>独立事件</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>P(A∩B) = P(A)·P(B)</span></span></code></pre></div><p><strong>全概率公式</strong>（选学）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>P(B) = Σ P(Aᵢ)·P(B|Aᵢ)</span></span></code></pre></div><hr><h3 id="类型4-分布列与期望-⭐" tabindex="-1">类型4：分布列与期望 ⭐ <a class="header-anchor" href="#类型4-分布列与期望-⭐" aria-label="Permalink to &quot;类型4：分布列与期望 ⭐&quot;">​</a></h3><p><strong>Step 1：确定随机变量X的所有可能取值</strong></p><p><strong>Step 2：计算每个取值的概率</strong></p><ul><li>P(X=xᵢ) = ?</li></ul><p><strong>Step 3：列出分布列</strong></p><table tabindex="0"><thead><tr><th style="text-align:center;">X</th><th style="text-align:center;">x₁</th><th style="text-align:center;">x₂</th><th style="text-align:center;">...</th><th style="text-align:center;">xₙ</th></tr></thead><tbody><tr><td style="text-align:center;">P</td><td style="text-align:center;">p₁</td><td style="text-align:center;">p₂</td><td style="text-align:center;">...</td><td style="text-align:center;">pₙ</td></tr></tbody></table><p><strong>Step 4：计算期望和方差</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>E(X) = x₁p₁ + x₂p₂ + ... + xₙpₙ</span></span>
<span class="line"><span>D(X) = (x₁-E(X))²p₁ + ... + (xₙ-E(X))²pₙ</span></span>
<span class="line"><span>     = E(X²) - [E(X)]²</span></span></code></pre></div><hr><h3 id="类型5-二项分布-⭐" tabindex="-1">类型5：二项分布 ⭐ <a class="header-anchor" href="#类型5-二项分布-⭐" aria-label="Permalink to &quot;类型5：二项分布 ⭐&quot;">​</a></h3><p><strong>识别</strong>：</p><ul><li>n次独立重复试验</li><li>每次试验只有两个结果（成功/失败）</li><li>每次成功概率为p</li></ul><p><strong>分布列</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>P(X=k) = C(n,k) · p^k · (1-p)^(n-k)</span></span></code></pre></div><p><strong>数字特征</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>E(X) = np</span></span>
<span class="line"><span>D(X) = np(1-p)</span></span></code></pre></div><hr><h3 id="类型6-超几何分布" tabindex="-1">类型6：超几何分布 <a class="header-anchor" href="#类型6-超几何分布" aria-label="Permalink to &quot;类型6：超几何分布&quot;">​</a></h3><p><strong>识别</strong>：</p><ul><li>从N个产品中取n个</li><li>其中有M个次品</li><li>求取到k个次品的概率</li></ul><p><strong>分布列</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>P(X=k) = C(M,k)·C(N-M,n-k) / C(N,n)</span></span></code></pre></div><p><strong>期望</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>E(X) = n·(M/N)</span></span></code></pre></div><hr><h3 id="类型7-统计案例-独立性检验" tabindex="-1">类型7：统计案例（独立性检验） <a class="header-anchor" href="#类型7-统计案例-独立性检验" aria-label="Permalink to &quot;类型7：统计案例（独立性检验）&quot;">​</a></h3><p><strong>Step 1：列出2×2列联表</strong></p><table tabindex="0"><thead><tr><th style="text-align:center;"></th><th style="text-align:center;">属性B₁</th><th style="text-align:center;">属性B₂</th><th style="text-align:center;">合计</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>属性A₁</strong></td><td style="text-align:center;">a</td><td style="text-align:center;">b</td><td style="text-align:center;">a+b</td></tr><tr><td style="text-align:center;"><strong>属性A₂</strong></td><td style="text-align:center;">c</td><td style="text-align:center;">d</td><td style="text-align:center;">c+d</td></tr><tr><td style="text-align:center;"><strong>合计</strong></td><td style="text-align:center;">a+c</td><td style="text-align:center;">b+d</td><td style="text-align:center;">n=a+b+c+d</td></tr></tbody></table><p><strong>Step 2：计算K²（卡方）统计量</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>K² = n(ad-bc)²/[(a+b)(c+d)(a+c)(b+d)]</span></span></code></pre></div><p><strong>Step 3：查表比较</strong></p><table tabindex="0"><thead><tr><th style="text-align:center;">P(K²≥k₀)</th><th style="text-align:center;">0.050</th><th style="text-align:center;">0.010</th><th style="text-align:center;">0.001</th></tr></thead><tbody><tr><td style="text-align:center;">k₀</td><td style="text-align:center;">3.841</td><td style="text-align:center;">6.635</td><td style="text-align:center;">10.828</td></tr></tbody></table><p><strong>Step 4：下结论</strong></p><ul><li>K² ≥ 3.841 → 有95%把握认为有关</li><li>K² ≥ 6.635 → 有99%把握认为有关</li><li>K² ≥ 10.828 → 有99.9%把握认为有关</li></ul><hr><h2 id="三、标准格式" tabindex="-1">三、标准格式 <a class="header-anchor" href="#三、标准格式" aria-label="Permalink to &quot;三、标准格式&quot;">​</a></h2><h3 id="分布列答题模板" tabindex="-1">分布列答题模板 <a class="header-anchor" href="#分布列答题模板" aria-label="Permalink to &quot;分布列答题模板&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>解：X的所有可能取值为0,1,2,3</span></span>
<span class="line"><span></span></span>
<span class="line"><span>P(X=0) = ... = ...</span></span>
<span class="line"><span>P(X=1) = ... = ...</span></span>
<span class="line"><span>P(X=2) = ... = ...</span></span>
<span class="line"><span>P(X=3) = ... = ...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>X的分布列为：</span></span>
<span class="line"><span>| X | 0 | 1 | 2 | 3 |</span></span>
<span class="line"><span>|---|---|---|---|---|</span></span>
<span class="line"><span>| P | p₁ | p₂ | p₃ | p₄ |</span></span>
<span class="line"><span></span></span>
<span class="line"><span>E(X) = 0·p₁ + 1·p₂ + 2·p₃ + 3·p₄ = ...</span></span></code></pre></div><h3 id="独立性检验答题模板" tabindex="-1">独立性检验答题模板 <a class="header-anchor" href="#独立性检验答题模板" aria-label="Permalink to &quot;独立性检验答题模板&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>解：假设H₀：...与...无关</span></span>
<span class="line"><span></span></span>
<span class="line"><span>列联表：</span></span>
<span class="line"><span>[表格]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>K² = n(ad-bc)²/[(a+b)(c+d)(a+c)(b+d)]</span></span>
<span class="line"><span>   = ...</span></span>
<span class="line"><span>   ≈ ...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>∵ K² &gt; 3.841（或6.635）</span></span>
<span class="line"><span>∴ 有95%（或99%）的把握认为...与...有关</span></span></code></pre></div><hr><h2 id="四、典型例题" tabindex="-1">四、典型例题 <a class="header-anchor" href="#四、典型例题" aria-label="Permalink to &quot;四、典型例题&quot;">​</a></h2><h3 id="例题1-分布列" tabindex="-1">例题1：分布列 <a class="header-anchor" href="#例题1-分布列" aria-label="Permalink to &quot;例题1：分布列&quot;">​</a></h3><p><strong>题目</strong>：袋中有3个红球、2个白球，任取2个，X表示取到的红球个数，求X的分布列和期望。</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>解：X的可能取值为0,1,2</span></span>
<span class="line"><span></span></span>
<span class="line"><span>P(X=0) = C(2,2)/C(5,2) = 1/10</span></span>
<span class="line"><span>P(X=1) = C(3,1)C(2,1)/C(5,2) = 6/10 = 3/5</span></span>
<span class="line"><span>P(X=2) = C(3,2)/C(5,2) = 3/10</span></span>
<span class="line"><span></span></span>
<span class="line"><span>分布列：</span></span>
<span class="line"><span>| X | 0 | 1 | 2 |</span></span>
<span class="line"><span>|---|---|---|---|</span></span>
<span class="line"><span>| P | 1/10 | 3/5 | 3/10 |</span></span>
<span class="line"><span></span></span>
<span class="line"><span>E(X) = 0×(1/10) + 1×(3/5) + 2×(3/10)</span></span>
<span class="line"><span>     = 0 + 3/5 + 3/5</span></span>
<span class="line"><span>     = 6/5</span></span></code></pre></div><hr><h3 id="例题2-独立性检验" tabindex="-1">例题2：独立性检验 <a class="header-anchor" href="#例题2-独立性检验" aria-label="Permalink to &quot;例题2：独立性检验&quot;">​</a></h3><p><strong>题目</strong>：调查100人，得列联表如下，问是否有95%把握认为性别与爱好有关？</p><table tabindex="0"><thead><tr><th style="text-align:center;"></th><th style="text-align:center;">喜欢</th><th style="text-align:center;">不喜欢</th><th style="text-align:center;">合计</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>男</strong></td><td style="text-align:center;">40</td><td style="text-align:center;">20</td><td style="text-align:center;">60</td></tr><tr><td style="text-align:center;"><strong>女</strong></td><td style="text-align:center;">20</td><td style="text-align:center;">20</td><td style="text-align:center;">40</td></tr><tr><td style="text-align:center;"><strong>合计</strong></td><td style="text-align:center;">60</td><td style="text-align:center;">40</td><td style="text-align:center;">100</td></tr></tbody></table><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>解：K² = 100×(40×20-20×20)²/(60×40×60×40)</span></span>
<span class="line"><span>       = 100×400²/(5760000)</span></span>
<span class="line"><span>       ≈ 2.778</span></span>
<span class="line"><span></span></span>
<span class="line"><span>∵ 2.778 &lt; 3.841</span></span>
<span class="line"><span>∴ 没有95%的把握认为性别与爱好有关</span></span></code></pre></div><hr><h2 id="五、易错点清单" tabindex="-1">五、易错点清单 <a class="header-anchor" href="#五、易错点清单" aria-label="Permalink to &quot;五、易错点清单&quot;">​</a></h2><h3 id="审题阶段" tabindex="-1">审题阶段 <a class="header-anchor" href="#审题阶段" aria-label="Permalink to &quot;审题阶段&quot;">​</a></h3><ul><li>[ ] 是有序还是无序？</li><li>[ ] 是放回还是不放回？</li><li>[ ] 是独立重复试验吗？</li></ul><h3 id="计算阶段" tabindex="-1">计算阶段 <a class="header-anchor" href="#计算阶段" aria-label="Permalink to &quot;计算阶段&quot;">​</a></h3><ul><li>[ ] 组合数计算是否正确？</li><li>[ ] 概率之和是否为1？</li><li>[ ] 期望计算是否正确？</li></ul><h3 id="检验阶段" tabindex="-1">检验阶段 <a class="header-anchor" href="#检验阶段" aria-label="Permalink to &quot;检验阶段&quot;">​</a></h3><ul><li>[ ] 分布列概率之和是否为1？</li><li>[ ] K²公式分子是否有平方？</li></ul><hr><h2 id="六、得分点提示" tabindex="-1">六、得分点提示 <a class="header-anchor" href="#六、得分点提示" aria-label="Permalink to &quot;六、得分点提示&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">步骤</th><th style="text-align:left;">得分点</th></tr></thead><tbody><tr><td style="text-align:center;">计数</td><td style="text-align:left;">写出组合数表达式</td></tr><tr><td style="text-align:center;">概率</td><td style="text-align:left;">写出基本事件数</td></tr><tr><td style="text-align:center;">分布列</td><td style="text-align:left;">列出表格</td></tr><tr><td style="text-align:center;">期望</td><td style="text-align:left;">写出计算公式</td></tr><tr><td style="text-align:center;">检验</td><td style="text-align:left;">写出K²计算过程</td></tr></tbody></table><hr><p><strong>文档编号</strong>: Math-Review-Routine-008<br><strong>版本</strong>: V1.0<br><strong>日期</strong>: 20260405</p>`,100)])])}const u=a(l,[["render",i]]);export{g as __pageData,u as default};
